#!/usr/bin/env node
/**
 * Migrates manually-defined sidebars.js files to autogenerated format.
 * For each doc entry in sidebars.js:
 *   - Adds sidebar_position frontmatter (preserves ordering)
 *   - Adds sidebar_icon frontmatter (if customProps.icon is set)
 * Then replaces each sidebars.js with autogenerated config.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');

const SECTIONS = [
  { id: 'pendle-v2',     folder: 'docs/pendle-v2',        ext: ['md', 'mdx'], sidebars: 'docs/pendle-v2/sidebars.js' },
  { id: 'boros-dev',     folder: 'docs/boros-dev-docs',   ext: ['md', 'mdx'], sidebars: 'docs/boros-dev-docs/sidebars.js' },
  { id: 'pendle-academy',folder: 'docs/pendle-academy',   ext: ['md', 'mdx'], sidebars: 'docs/pendle-academy/sidebars.js' },
  { id: 'boros-docs',    folder: 'docs/boros-docs',       ext: ['md', 'mdx'], sidebars: 'docs/boros-docs/sidebars.js' },
  { id: 'boros-academy', folder: 'docs/boros-academy',    ext: ['md', 'mdx'], sidebars: 'docs/boros-academy/sidebars.js' },
];

// Walk sidebar items and collect { docId, position, icon, categoryPath }
// position = index within its parent (1-based), categoryPath = array of parent category labels
function collectDocs(items, categoryPath = [], result = []) {
  let position = 1;
  for (const item of items) {
    if (item.type === 'doc') {
      result.push({
        id: item.id,
        position,
        icon: item.customProps?.icon || null,
        categoryPath,
      });
      position++;
    } else if (item.type === 'category') {
      // Category itself doesn't get a file entry, but we record its position
      // so subcategories can be ordered relative to siblings
      if (item.items && item.items.length) {
        collectDocs(item.items, [...categoryPath, item.label], result);
      }
      position++;
    }
    // skip 'link' type items (external links, no file)
  }
  return result;
}

function parseFrontmatter(content) {
  const match = content.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?([\s\S]*)$/);
  if (!match) return { fm: {}, fmRaw: null, body: content };
  const fmRaw = match[1];
  const body = match[2];
  const fm = {};
  for (const line of fmRaw.split('\n')) {
    const m = line.match(/^([\w_-]+):\s*(.+)$/);
    if (m) {
      const v = m[2].trim().replace(/^['"]|['"]$/g, '');
      fm[m[1]] = v;
    }
  }
  return { fm, fmRaw, body };
}

function buildFrontmatter(fm) {
  const entries = Object.entries(fm).filter(([, v]) => v !== undefined && v !== null && v !== '');
  if (!entries.length) return '';
  const lines = entries.map(([k, v]) => {
    if (typeof v === 'string' && /[:#\[\]{}&*!|>'"%@`]/.test(v)) return `${k}: '${v}'`;
    return `${k}: ${v}`;
  });
  return `---\n${lines.join('\n')}\n---\n`;
}

function findFile(folder, docId, exts) {
  for (const ext of exts) {
    const p = path.join(ROOT, folder, docId + '.' + ext);
    if (fs.existsSync(p)) return p;
  }
  // Also try with different casing — some ids use numeric prefixes
  return null;
}

let patchedCount = 0;
let missingCount = 0;

for (const section of SECTIONS) {
  console.log(`\n── ${section.id} ──`);

  // Load the sidebars module
  const sidebarsPath = path.join(ROOT, section.sidebars);
  // Clear require cache so we can reload
  delete require.cache[require.resolve(sidebarsPath)];
  const sidebarsModule = require(sidebarsPath);

  // Get the sidebar array (first export value)
  const sidebarKey = Object.keys(sidebarsModule)[0];
  const sidebarItems = sidebarsModule[sidebarKey];

  const docs = collectDocs(sidebarItems);
  console.log(`  Found ${docs.length} doc entries`);

  for (const doc of docs) {
    const filePath = findFile(section.folder, doc.id, section.ext);
    if (!filePath) {
      console.log(`  ⚠ MISSING: ${doc.id}`);
      missingCount++;
      continue;
    }

    const raw = fs.readFileSync(filePath, 'utf8');
    const { fm, body } = parseFrontmatter(raw);

    let changed = false;

    // Set sidebar_position if not already set
    if (!fm.sidebar_position) {
      fm.sidebar_position = doc.position;
      changed = true;
    }

    // Set sidebar_icon if customProps.icon existed and frontmatter doesn't already have it
    if (doc.icon && !fm.sidebar_icon) {
      fm.sidebar_icon = doc.icon;
      changed = true;
    }

    if (changed) {
      // Rebuild file: frontmatter + body
      const newContent = buildFrontmatter(fm) + body;
      fs.writeFileSync(filePath, newContent, 'utf8');
      console.log(`  ✓ ${doc.id} (pos=${doc.position}${doc.icon ? ', icon=' + doc.icon : ''})`);
      patchedCount++;
    } else {
      console.log(`  · ${doc.id} (already has frontmatter)`);
    }
  }
}

console.log(`\nDone. Patched ${patchedCount} files. Missing: ${missingCount}.`);
